mapper.update:
update course_resource cr
join course c on c.id = cr.course_id
set cr.title = #{title},
    cr.description = #{description},
    cr.category = #{category}
where cr.id = #{resourceId}
  and cr.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and cr.status = 1
  and c.status = 1

update course_resource cr
join course c on c.id = cr.course_id
set cr.status = 0
where cr.id = #{resourceId}
  and cr.course_id = #{courseId}
  and c.teacher_id = #{teacherId}
  and cr.status = 1
  and c.status = 1
